"use client";
import { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import { AuthContext } from '@/context/AuthContext';
import { CheckCircle, XCircle, Loader2, Eye, Edit3, Save, X, Bot, Image as ImageIcon } from 'lucide-react';
import { useRouter } from 'next/navigation';

export default function AdminPanel() {
  const { user, token } = useContext(AuthContext);
  const [pendingPosts, setPendingPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const router = useRouter();

  const [previewPost, setPreviewPost] = useState(null);

  // סטייטים לעריכה (הוספנו סטייט לתמונה)
  const [editingPostId, setEditingPostId] = useState(null);
  const [editTitle, setEditTitle] = useState("");
  const [editContent, setEditContent] = useState("");
  const [editCoverImage, setEditCoverImage] = useState("");

  useEffect(() => {
    if (!token && !user) { setLoading(false); return; }
    if (user && user.role !== 'admin') { router.push('/'); return; }

    const fetchPendingPosts = async () => {
      try {
        const res = await axios.get(`${process.env.NEXT_PUBLIC_API_URL}/posts/pending`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setPendingPosts(res.data);
      } catch (error) {
        console.error("שגיאה במשיכת פוסטים ממתינים:", error);
      } finally {
        setLoading(false);
      }
    };

    if (token) fetchPendingPosts();
  }, [user, token, router]);

  const handleStatusUpdate = async (id, newStatus) => {
    try {
      await axios.put(`${process.env.NEXT_PUBLIC_API_URL}/posts/${id}/status`,
        { status: newStatus },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setPendingPosts(prevPosts => prevPosts.filter(post => post._id !== id));
      setPreviewPost(null);
    } catch (error) {
      alert('שגיאה בעדכון הסטטוס.');
    }
  };

  // פונקציית תחילת עריכה (מושכת גם את התמונה הנוכחית)
  const startEditing = (post) => {
    setEditingPostId(post._id);
    setEditTitle(post.title);
    setEditContent(post.content);
    setEditCoverImage(post.coverImage || ""); // שומרים את הקישור לתמונה
  };

  // פונקציית השמירה (שולחת גם את התמונה החדשה)
  const handleUpdatePost = async (id) => {
    try {
      await axios.put(`${process.env.NEXT_PUBLIC_API_URL}/posts/${id}`,
        { title: editTitle, content: editContent, coverImage: editCoverImage }, // שולחים coverImage
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      // עדכון המסך באופן מיידי
      setPendingPosts(posts => posts.map(p => 
        p._id === id ? { ...p, title: editTitle, content: editContent, coverImage: editCoverImage } : p
      ));
      setEditingPostId(null);
    } catch (error) {
      alert("שגיאה בשמירת השינויים.");
    }
  };

  if (loading) return <div className="flex justify-center items-center min-h-screen"><Loader2 className="w-12 h-12 animate-spin text-indigo-500" /></div>;
  if (!user || user.role !== 'admin') return <div className="min-h-screen flex items-center justify-center text-rose-500">אין הרשאה.</div>;

  return (
    <main className="min-h-screen bg-slate-50 py-12 px-4 md:px-8 relative">
      <div className="max-w-5xl mx-auto">
        <h1 className="text-4xl font-black text-slate-900 mb-8 tracking-tight">
          פאנל ניהול <span className="text-rose-500">אישור פוסטים (AI)</span>
        </h1>
        
        {pendingPosts.length === 0 ? (
          <div className="bg-white p-10 rounded-2xl shadow-sm text-center border border-slate-100">
            <p className="text-xl text-slate-500">אין פוסטים הממתינים לאישור כרגע. סוכני ה-AI נחים! 😴</p>
          </div>
        ) : (
          <div className="flex flex-col gap-6">
            {pendingPosts.map(post => (
              <div key={post._id} className="bg-white p-6 rounded-2xl shadow-sm hover:shadow-md transition-shadow border border-slate-100 flex flex-col md:flex-row gap-6 items-start">
                
                {/* הצגת התמונה במצב רגיל (לא בעריכה) */}
                {post.coverImage && !editingPostId && (
                  <img src={post.coverImage} alt={post.title} className="w-full md:w-56 h-40 object-cover rounded-xl border border-slate-100" />
                )}
                
                <div className="flex-grow w-full">
                  {editingPostId === post._id ? (
                    /* מצב עריכה */
                    <div className="flex flex-col gap-4 w-full">
                      <div className="text-indigo-600 text-sm font-bold flex items-center gap-1"><Edit3 className="w-4 h-4"/> עריכת פוסט טרם פרסום</div>
                      
                      <input type="text" value={editTitle} onChange={(e) => setEditTitle(e.target.value)} className="text-xl font-bold bg-slate-50 border border-slate-200 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="כותרת הפוסט..." />
                      
                      {/* אזור עריכת התמונה */}
                      <div className="flex flex-col gap-2 bg-slate-50 p-4 rounded-xl border border-slate-200">
                        <label className="text-sm font-bold text-slate-700 flex items-center gap-2">
                          <ImageIcon className="w-4 h-4" /> קישור לתמונת קאבר (URL)
                        </label>
                        <input 
                          type="text" 
                          value={editCoverImage} 
                          onChange={(e) => setEditCoverImage(e.target.value)} 
                          className="bg-white border border-slate-200 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none text-sm dir-ltr text-left" 
                          placeholder="https://example.com/image.jpg" 
                        />
                        {/* תצוגה מקדימה חיה של התמונה החדשה */}
                        {editCoverImage && (
                          <div className="mt-2 rounded-lg overflow-hidden h-32 w-full md:w-64 bg-slate-200 border border-slate-200">
                            <img src={editCoverImage} alt="Preview" className="w-full h-full object-cover" onError={(e) => e.target.style.display = 'none'} />
                          </div>
                        )}
                      </div>

                      <textarea value={editContent} onChange={(e) => setEditContent(e.target.value)} rows="6" className="bg-slate-50 border border-slate-200 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none resize-none" placeholder="תוכן הפוסט..." />
                      
                      <div className="flex gap-3 mt-2">
                        <button onClick={() => setEditingPostId(null)} className="flex items-center gap-1 text-slate-500 hover:text-slate-700 px-4 py-2 font-medium bg-slate-100 rounded-xl"><X className="w-4 h-4" /> ביטול</button>
                        <button onClick={() => handleUpdatePost(post._id)} className="flex items-center gap-1 bg-indigo-600 hover:bg-indigo-700 text-white px-5 py-2 rounded-xl font-medium transition"><Save className="w-4 h-4" /> שמור שינויים</button>
                      </div>
                    </div>
                  ) : (
                    /* מצב רגיל בטבלה (כמו קודם) */
                    <>
                      <h2 className="text-2xl font-bold text-slate-800 mb-2">{post.title}</h2>
                      <p className="text-slate-600 mb-4 line-clamp-2">{post.content}</p>
                      
                      <div className="flex flex-wrap items-center gap-3">
                        <button onClick={() => handleStatusUpdate(post._id, 'published')} className="flex items-center gap-1.5 bg-emerald-500 text-white px-4 py-2 rounded-xl hover:bg-emerald-600 transition font-medium text-sm">
                          <CheckCircle className="w-4 h-4" /> אשר ופרסם
                        </button>
                        <button onClick={() => setPreviewPost(post)} className="flex items-center gap-1.5 bg-indigo-50 text-indigo-600 px-4 py-2 rounded-xl hover:bg-indigo-100 transition font-medium text-sm">
                          <Eye className="w-4 h-4" /> תצוגה מלאה
                        </button>
                        <button onClick={() => startEditing(post)} className="flex items-center gap-1.5 bg-slate-100 text-slate-700 px-4 py-2 rounded-xl hover:bg-slate-200 transition font-medium text-sm">
                          <Edit3 className="w-4 h-4" /> ערוך
                        </button>
                        <button onClick={() => handleStatusUpdate(post._id, 'rejected')} className="flex items-center gap-1.5 bg-rose-50 text-rose-600 px-4 py-2 rounded-xl hover:bg-rose-100 transition font-medium text-sm ml-auto">
                          <XCircle className="w-4 h-4" /> דחה פוסט
                        </button>
                      </div>
                    </>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* תצוגה מקדימה (Modal) נשאר ללא שינוי... */}
      {previewPost && (
        <div className="fixed inset-0 bg-slate-900/60 z-50 flex justify-center items-center p-4 backdrop-blur-sm overflow-y-auto">
          {/* ... קוד ה-Modal שהיה לנו קודם ... */}
          <div className="bg-white w-full max-w-4xl rounded-3xl shadow-2xl overflow-hidden my-8 relative flex flex-col max-h-[90vh]">
            <button onClick={() => setPreviewPost(null)} className="absolute top-4 right-4 bg-black/50 hover:bg-black/70 text-white p-2 rounded-full transition z-10"><X className="w-6 h-6" /></button>
            <div className="overflow-y-auto flex-grow">
              {previewPost.coverImage && <img src={previewPost.coverImage} alt={previewPost.title} className="w-full h-64 md:h-80 object-cover" />}
              <div className="p-8 md:p-12">
                <div className="flex flex-wrap gap-2 mb-6">
                  {previewPost.tags?.map((tag, idx) => <span key={idx} className="bg-indigo-50 text-indigo-600 px-3 py-1 rounded-full text-sm font-semibold">{tag}</span>)}
                </div>
                <h1 className="text-3xl md:text-5xl font-black text-slate-900 mb-6 leading-tight">{previewPost.title}</h1>
                <p className="text-lg text-slate-700 leading-relaxed whitespace-pre-wrap">{previewPost.content}</p>
              </div>
            </div>
            <div className="bg-slate-50 border-t border-slate-200 p-4 md:px-8 flex items-center justify-between mt-auto">
              <span className="text-slate-500 font-medium text-sm">הפוסט ממתין לאישור מנהל</span>
              <div className="flex gap-3">
                <button onClick={() => handleStatusUpdate(previewPost._id, 'rejected')} className="px-5 py-2.5 rounded-xl font-bold text-rose-600 hover:bg-rose-100 transition">דחה ומחק</button>
                <button onClick={() => handleStatusUpdate(previewPost._id, 'published')} className="flex items-center gap-2 bg-emerald-500 hover:bg-emerald-600 text-white px-6 py-2.5 rounded-xl font-bold transition shadow-sm"><CheckCircle className="w-5 h-5" /> פרסם לאתר עכשיו</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </main>
  );
}